<?php
declare(strict_types=1);
require __DIR__ . '/app.php';
require __DIR__ . '/ledger-tools.php';
$config = lqr_config();
$state = lqr_load_state();
if (empty($_SESSION['lqr_admin_authed'])) { header('Location: admin.php'); exit; }
$rows = lqr_ledger_rows($state);
$filter = [
    'event' => (string)($_GET['event'] ?? ''),
    'result' => (string)($_GET['result'] ?? ''),
    'reward_id' => (string)($_GET['reward_id'] ?? ''),
    'actor' => (string)($_GET['actor'] ?? ''),
];
$filtered = lqr_ledger_filtered_rows($rows, $filter);
$metrics = lqr_ledger_metrics($rows);
$chain = lqr_ledger_chain($rows, $filter['reward_id']);
?>
<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Partner Ledger | Local Quest Rewards</title><link rel="stylesheet" href="assets/portal.css"><style>.lq-ledger-hero{background:linear-gradient(135deg,#101828,#211816 46%,#4b1729);color:#fff;border-radius:18px;padding:32px;margin-bottom:22px;box-shadow:var(--lq-shadow)}.lq-ledger-hero h1{font-size:clamp(36px,6vw,68px);line-height:.92;letter-spacing:-.08em;margin:12px 0}.lq-ledger-hero p{color:#ffe6ef;max-width:900px}.lq-ledger-grid{display:grid;grid-template-columns:repeat(5,minmax(0,1fr));gap:14px;margin:22px 0}.lq-ledger-filter{display:grid;grid-template-columns:repeat(5,minmax(0,1fr));gap:10px;margin-bottom:18px}.lq-ledger-filter input,.lq-ledger-filter select{width:100%;border:1px solid var(--lq-border);border-radius:10px;padding:10px;background:#fff}.lq-ledger-row{display:grid;grid-template-columns:160px 170px 90px minmax(0,1fr) 160px;gap:10px;align-items:start;border:1px solid var(--lq-border);border-radius:12px;background:#fff;padding:12px;margin-top:10px}.lq-ledger-row code{font-size:11px;word-break:break-all}.lq-ledger-json{background:#f7f8fb;border-radius:8px;padding:10px;font-size:11px;white-space:pre-wrap;overflow:auto}@media(max-width:1100px){.lq-ledger-grid,.lq-ledger-filter,.lq-ledger-row{grid-template-columns:1fr}}</style></head><body class="lq-portal"><div class="lq-shell"><header class="lq-topbar"><div class="lq-brand"><span class="lq-logo">LQ</span><span>Local Quest</span></div><div class="lq-top-actions"><a class="lq-upgrade" href="app-console-admin.php">App Console</a><a class="lq-upgrade" href="admin-programs.php">Program Builder</a><a class="lq-upgrade" href="developer-starter.php">Developer Starter</a></div></header><aside class="lq-sidebar"><a class="lq-side-link" href="admin.php"><span class="lq-side-icon">⚙</span><span class="lq-side-label">Admin</span></a><a class="lq-side-link" href="app-console-admin.php"><span class="lq-side-icon">APP</span><span class="lq-side-label">App Console</span></a><a class="lq-side-link active" href="admin-ledger.php"><span class="lq-side-icon">LED</span><span class="lq-side-label">Ledger</span></a><a class="lq-side-link" href="admin-developer-readiness.php"><span class="lq-side-icon">QA</span><span class="lq-side-label">Readiness</span></a><a class="lq-side-link" href="webhook.php"><span class="lq-side-icon">◷</span><span class="lq-side-label">Webhook status</span></a></aside><main class="lq-main"><section class="lq-ledger-hero"><span class="lq-eyebrow">Partner activity evidence</span><h1>Transaction Ledger.</h1><p>Track every outside-app lifecycle event: account link, reward issue, status check, claim report, webhook verification, and wallet state evidence.</p></section><div class="lq-ledger-grid"><div class="lq-kpi"><span>Total</span><strong><?= number_format((int)$metrics['total']) ?></strong></div><div class="lq-kpi"><span>API calls</span><strong><?= number_format((int)$metrics['api_calls']) ?></strong></div><div class="lq-kpi"><span>Issues</span><strong><?= number_format((int)$metrics['reward_issues']) ?></strong></div><div class="lq-kpi"><span>Claims</span><strong><?= number_format((int)$metrics['claims_reported']) ?></strong></div><div class="lq-kpi"><span>Failures</span><strong><?= number_format((int)$metrics['failed']) ?></strong></div></div><section class="lq-card"><div class="lq-card-head"><div><h2>Filters</h2><p>Search by event, result, reward ID, or actor.</p></div><a class="lq-btn soft" href="admin-ledger.php">Reset</a></div><form class="lq-ledger-filter" method="get"><input name="event" placeholder="event" value="<?= lqr_h($filter['event']) ?>"><select name="result"><option value="">any result</option><option value="success" <?= $filter['result']==='success'?'selected':'' ?>>success</option><option value="failed" <?= $filter['result']==='failed'?'selected':'' ?>>failed</option></select><input name="reward_id" placeholder="reward id" value="<?= lqr_h($filter['reward_id']) ?>"><input name="actor" placeholder="actor" value="<?= lqr_h($filter['actor']) ?>"><button class="lq-btn primary">Filter</button></form><?php if ($filter['reward_id'] !== ''): ?><div class="lq-notice">Lifecycle chain for reward <?= lqr_h($filter['reward_id']) ?>: <?= number_format(count($chain)) ?> events.</div><?php endif; ?><?php foreach (array_slice($filtered, 0, 80) as $row): ?><article class="lq-ledger-row"><div><strong><?= lqr_h((string)$row['event']) ?></strong><div class="lq-meta"><?= lqr_h((string)$row['at']) ?></div><span class="lq-pill <?= ($row['result'] ?? '') === 'success' ? 'green' : 'amber' ?>"><?= lqr_h((string)$row['result']) ?></span></div><div><div class="lq-meta">Actor</div><code><?= lqr_h((string)$row['actor']) ?></code><div class="lq-meta" style="margin-top:8px">App</div><code><?= lqr_h((string)$row['app_id']) ?></code></div><div><div class="lq-meta">Status</div><strong><?= lqr_h((string)$row['status']) ?></strong></div><div><div><?= lqr_h((string)$row['message']) ?></div><div class="lq-meta">Program <code><?= lqr_h((string)$row['program_id']) ?></code> · Template <code><?= lqr_h((string)$row['template_id']) ?></code> · Quest <code><?= lqr_h((string)$row['quest_id']) ?></code></div><div class="lq-meta">Reward <code><?= lqr_h((string)$row['reward_id']) ?></code> · Item <code><?= lqr_h((string)$row['item_id']) ?></code></div></div><pre class="lq-ledger-json"><?= lqr_h(json_encode($row['context'], JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES)) ?></pre></article><?php endforeach; ?><?php if (!$filtered): ?><div class="lq-notice">No ledger rows match this filter.</div><?php endif; ?></section></main></div></body></html>
